var stops = parseInt(ndStops);
    var base = parseFloat(baseShutter);
    var factor = Math.pow(2, stops);
    var newShutter = base * factor;
    var lightPct = (1 / factor) * 100;
    var shutterStr;
    if (newShutter >= 60) shutterStr = fmt(newShutter / 60, 1) + ' minutes';
    else if (newShutter >= 1) shutterStr = fmt(newShutter, 1) + ' seconds';
    else shutterStr = '1/' + fmt(1/newShutter, 0) + 's';
    var tip;
    if (newShutter >= 30) tip = 'Use bulb mode, remote shutter release, and sturdy tripod. Cover viewfinder to prevent light leak.';
    else if (newShutter >= 1) tip = 'Use tripod and timer/remote. Mirror lock-up recommended for DSLRs.';
    else tip = 'Handheld may work with stabilization. Tripod recommended for sharpest results.';
    document.getElementById('newShutter').textContent = shutterStr;
    document.getElementById('filterFactor').textContent = factor + '× (ND' + factor + ')';
    document.getElementById('lightReduction').textContent = fmt(lightPct, stops > 6 ? 4 : 2) + '% of original light (' + stops + ' stops)';
    document.getElementById('tip').textContent = tip;

var range = endFreq - startFreq;
    var channels = Math.floor(range / channelSpacing);
    var sweepTimeMs = channels * sweepRate;
    var sweepTimeSec = sweepTimeMs / 1000;
    var sessionMs = sessionMinutes * 60 * 1000;
    var sweepsPerSession = Math.floor(sessionMs / sweepTimeMs);
    var syllableMs = 250;
    var channelsPerSyllable = Math.floor(syllableMs / sweepRate);
    document.getElementById('totalChannels').textContent = fmt(channels, 0) + ' channels in ' + fmt(range, 1) + ' MHz range';
    document.getElementById('fullSweepTime').textContent = fmt(sweepTimeSec, 1) + ' seconds per full sweep';
    document.getElementById('sweepsPerSession').textContent = fmt(sweepsPerSession, 0) + ' complete sweeps in ' + sessionMinutes + ' min';
    document.getElementById('responseWindow').textContent = sweepRate + 'ms per channel (' + channelsPerSyllable + ' channels per syllable at ' + syllableMs + 'ms/syllable)';

var weekly = dailySpend * daysPerWeek;
    var monthly = weekly * 4.333;
    var yearly = weekly * 52;
    var totalSpent = yearly * years;
    var monthlyInvest = monthly;
    var monthlyRate = returnRate / 100 / 12;
    var months = years * 12;
    var fv = monthlyInvest * ((Math.pow(1 + monthlyRate, months) - 1) / monthlyRate);
    var diff = fv - totalSpent;
    document.getElementById('weekly').textContent = dollar(weekly) + '/week (' + dollar(monthly) + '/month)';
    document.getElementById('yearly').textContent = dollar(yearly) + '/year';
    document.getElementById('totalSpent').textContent = dollar(totalSpent);
    document.getElementById('ifInvested').textContent = dollar(fv) + ' (at ' + returnRate + '% annual return)';
    document.getElementById('difference').textContent = dollar(diff) + ' in growth from compound interest';

var baseInches = {lawn: 1, vegetable: 1.25, flower: 1, shrub: 0.75, tree: 0.5};
    var base = baseInches[plantType];
    var soilFactor = parseFloat(soilType);
    var tempFactor = parseFloat(temperature);
    var weeklyInches = base * tempFactor - recentRain;
    weeklyInches = Math.max(0, weeklyInches);
    var gallonsPerSqFt = weeklyInches * 0.623;
    var totalGallons = gallonsPerSqFt * sqft;
    var sessions;
    if (soilFactor <= 0.7) sessions = 3;
    else if (soilFactor <= 1.0) sessions = 2;
    else sessions = 1;
    if (tempFactor >= 1.3) sessions = Math.min(sessions + 1, 4);
    var perSession = totalGallons / sessions;
    var scheduleText = sessions + ' times per week';
    if (weeklyInches <= 0) scheduleText = 'No additional watering needed this week (sufficient rain)';
    document.getElementById('weeklyNeed').textContent = fmt(weeklyInches, 2) + ' inches/week';
    document.getElementById('gallonsPerWeek').textContent = fmt(totalGallons, 0) + ' gallons';
    document.getElementById('wateringSchedule').textContent = scheduleText;
    document.getElementById('perSession').textContent = weeklyInches > 0 ? fmt(perSession, 0) + ' gallons per session (' + fmt(perSession / sqft * 1.604, 2) + '" per session)' : 'N/A — rain is sufficient';
